1010→    /// macOS unflipped: visual bottom = minY ≈ 0, scroll down = decrease Y
1011→    private func scrollPageDownOrNext() {
1012→        let clipView = scrollView.contentView
1013→        let visibleHeight = clipView.bounds.height
1014→        let currentMinY = clipView.bounds.minY
1015→
1016→        // Continuous mode: scroll only, never navigate to next image
1017→        if settings.continuousScrollEnabled {
1018→            guard let range = scrollRange(for: scrollView.contentInsets) else { return }
1019→            let newY = max(currentMinY - visibleHeight, range.minY)
1020→            clipView.scroll(to: NSPoint(x: clipView.bounds.minX, y: newY))
1021→            scrollView.reflectScrolledClipView(clipView)
1022→            return
1023→        }
1024→
1025→        // Visual bottom in unflipped coords = minY near 0
1026→        if currentMinY <= Constants.scrollEdgeThreshold {
1027→            goToNextImage()
1028→        } else {
1029→            let newY = max(currentMinY - visibleHeight, 0)
